import{c as t,Q as a,j as s,m as r}from"./chunks/framework.rlpw0eGz.js";const c=JSON.parse('{"title":"Memoh Documentation","description":"","frontmatter":{},"headers":[],"relativePath":"index.md","filePath":"index.md","lastUpdated":1778736656000}'),o={name:"index.md"};function n(i,e,l,d,m,h){return a(),s("div",null,[...e[0]||(e[0]=[r('<h1 id="memoh-documentation" tabindex="-1">Memoh Documentation <a class="header-anchor" href="#memoh-documentation" aria-label="Permalink to &quot;Memoh Documentation&quot;">​</a></h1><p>Memoh(/ˈmemoʊ/) is a multi-member, structured long-memory AI agent platform. Create bots with independent workspaces, persistent memory, tool access, and channel integrations across Telegram, Discord, Lark (Feishu), QQ, Matrix, Misskey, DingTalk, WeCom, WeChat, WeChat Official Account, Email, and Web.</p><p>Memoh ships in two forms:</p><ul><li><strong>Desktop</strong> for personal and local use. The native app starts its own local server, embedded Qdrant, storage, and bundled CLI.</li><li><strong>Server Deploy</strong> for always-on, multi-user, multi-tenant, or channel-facing deployments.</li></ul><h2 id="start-here" tabindex="-1">Start Here <a class="header-anchor" href="#start-here" aria-label="Permalink to &quot;Start Here&quot;">​</a></h2><ul><li><strong><a href="/installation/">Installation Overview</a></strong> — Choose Desktop or Server Deploy.</li><li><strong><a href="/installation/desktop.html">Desktop Installation</a></strong> — Install the native local client.</li><li><strong><a href="/installation/docker.html">Server Deploy</a></strong> — Run Memoh with Docker Compose.</li><li><strong><a href="/getting-started/provider-and-model.html">Providers And Models</a></strong> — Set up providers, client types, and model roles.</li><li><strong><a href="/getting-started/bot.html">Bot Setup</a></strong> — Create a bot and configure its main tabs.</li><li><strong><a href="/getting-started/sessions.html">Sessions</a></strong> — Understand chat vs discuss sessions, status panels, and routing.</li></ul><h2 id="feature-guides" tabindex="-1">Feature Guides <a class="header-anchor" href="#feature-guides" aria-label="Permalink to &quot;Feature Guides&quot;">​</a></h2><ul><li><strong><a href="/installation/workspace-backends.html">Workspace Backends</a></strong> — Choose container and local workspace runtimes.</li><li><strong><a href="/getting-started/browser-computer-use.html">Browser / Computer Use</a></strong> — Operate headed workspace browsers and GUI desktops.</li><li><strong><a href="/getting-started/files.html">Files</a></strong> — Browse and edit the bot workspace filesystem.</li><li><strong><a href="/getting-started/channels.html">Channels</a></strong> — Platform overview and links to per-channel guides.</li><li><strong><a href="/getting-started/access.html">Access Control</a></strong> — ACL presets, rule ordering, and scoped access.</li><li><strong><a href="/getting-started/skills.html">Skills</a></strong> — Managed skills, effective/shadowed states, and adoption workflow.</li><li><strong><a href="/getting-started/supermarket.html">Supermarket</a></strong> — Install skills and MCP templates from the catalog.</li><li><strong><a href="/getting-started/mcp.html">MCP</a></strong> — Configure tool servers, OAuth, probing, import/export.</li><li><strong><a href="/getting-started/memory.html">Memory</a></strong> — Long-term memory providers and memory compaction.</li><li><strong><a href="/getting-started/compaction.html">Context Compaction</a></strong> — Reduce active session context size without changing stored memory.</li><li><strong><a href="/getting-started/slash-commands.html">Slash Commands</a></strong> — Learn the command model and daily control surface.</li></ul>',8)])])}const p=t(o,[["render",n]]);export{c as __pageData,p as default};
